import java.util.Scanner;
import java.nio.charset.StandardCharsets;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter your name: ");
        String input = scanner.nextLine();

        // Ensure input length does not exceed buffer size
        int bufferSize = 10;
        byte[] buffer = new byte[bufferSize];

        // Copy input bytes to buffer with proper length checking
        byte[] inputBytes = input.getBytes(StandardCharsets.UTF_8);
        int lengthToCopy = Math.min(inputBytes.length, bufferSize);
        System.arraycopy(inputBytes, 0, buffer, 0, lengthToCopy);

        System.out.println("Hello, " + new String(buffer, 0, lengthToCopy, StandardCharsets.UTF_8));
    }
}

### Explanation:
취약유형: Buffer Overflow
